const body = $input.first().json.body;
if (!body.events || body.events.length === 0) return [];

const results = [];
for (const event of body.events) {
  if (event.type !== 'message') continue;
  const replyToken = event.replyToken;
  const userId = event.source.userId;
  const msgType = event.message.type;

  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth() + 1;
  const day = now.getDate();
  const today = `${year}/${String(month).padStart(2,'0')}/${String(day).padStart(2,'0')}`;
  const fileName = `経営管理_${year}年${month}月.xlsx`;

  // 画像メッセージ（レシート）
  if (msgType === 'image') {
    results.push({ json: { valid: true, messageType: 'image', messageId: event.message.id, replyToken, userId, fileName, year, month } });
    continue;
  }

  if (msgType !== 'text') continue;
  const text = event.message.text.trim();

  const extract = (label, str) => {
    const m = str.match(new RegExp(label + '[：:]\\s*(.+)'));
    return m ? m[1].trim() : null;
  };
  const toNum = (s) => s ? parseInt(s.replace(/[,，￥¥\s]/g, '')) || 0 : 0;
  const replyError = (msg) => results.push({ json: { valid: false, replyToken, userId, errorMessage: msg } });

  // 照会系コマンド
  if (text === '未払い確認') {
    results.push({ json: { valid: true, messageType: 'query_unpaid', replyToken, userId, fileName, year, month } });
    continue;
  }
  if (text === '未入金確認') {
    results.push({ json: { valid: true, messageType: 'query_unreceived', replyToken, userId, fileName, year, month } });
    continue;
  }
  if (text === '今月サマリー') {
    results.push({ json: { valid: true, messageType: 'query_summary', replyToken, userId, fileName, year, month } });
    continue;
  }

  // 経費
  if (text.startsWith('経費')) {
    const category = extract('種類', text);
    const amount = extract('金額', text);
    const store = extract('店名', text);
    const missing = [];
    if (!category) missing.push('種類');
    if (!amount) missing.push('金額');
    if (!store) missing.push('店名');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    results.push({ json: {
      valid: true, messageType: 'expense', replyToken, userId, fileName, year, month,
      date: extract('日付', text) || today,
      category,
      paymentMethod: extract('支払方法', text) || '現金',
      store,
      project: extract('案件', text) || '',
      amount: toNum(amount),
      note: extract('備考', text) || ''
    }});
    continue;
  }

  // 外注請求
  if (text.startsWith('外注請求')) {
    const vendor = extract('業者', text);
    const project = extract('案件', text);
    const amount = extract('金額', text);
    const missing = [];
    if (!vendor) missing.push('業者');
    if (!project) missing.push('案件');
    if (!amount) missing.push('金額');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    const amtNum = toNum(amount);
    const taxRaw = extract('消費税', text);
    const taxNum = taxRaw ? toNum(taxRaw) : Math.round(amtNum * 0.1);
    const invDate = extract('請求日', text) || today;
    results.push({ json: {
      valid: true, messageType: 'subcontractor_invoice', replyToken, userId, fileName, year, month,
      registrationDate: invDate, vendor, project,
      amountExTax: amtNum, tax: taxNum, total: amtNum + taxNum,
      invoiceDate: invDate
    }});
    continue;
  }

  // 外注支払
  if (text.startsWith('外注支払')) {
    const vendor = extract('業者', text);
    const amount = extract('金額', text);
    const paymentDate = extract('支払日', text);
    const missing = [];
    if (!vendor) missing.push('業者');
    if (!amount) missing.push('金額');
    if (!paymentDate) missing.push('支払日');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    results.push({ json: {
      valid: true, messageType: 'subcontractor_payment', replyToken, userId, fileName, year, month,
      vendor, paymentDate, paymentAmount: toNum(amount)
    }});
    continue;
  }

  // 売上
  if (text.startsWith('売上')) {
    const client = extract('得意先', text);
    const project = extract('案件', text);
    const amount = extract('金額', text);
    const missing = [];
    if (!client) missing.push('得意先');
    if (!project) missing.push('案件');
    if (!amount) missing.push('金額');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    const amtNum = toNum(amount);
    const taxRaw = extract('消費税', text);
    const taxNum = taxRaw ? toNum(taxRaw) : Math.round(amtNum * 0.1);
    const invDate = extract('請求日', text) || today;
    results.push({ json: {
      valid: true, messageType: 'sales', replyToken, userId, fileName, year, month,
      registrationDate: invDate, client, project,
      amountExTax: amtNum, tax: taxNum, total: amtNum + taxNum,
      invoiceDate: invDate,
      dueDate: extract('支払期限', text) || ''
    }});
    continue;
  }

  // 入金
  if (text.startsWith('入金')) {
    const client = extract('得意先', text);
    const amount = extract('金額', text);
    const receivedDate = extract('入金日', text);
    const missing = [];
    if (!client) missing.push('得意先');
    if (!amount) missing.push('金額');
    if (!receivedDate) missing.push('入金日');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    results.push({ json: {
      valid: true, messageType: 'payment_received', replyToken, userId, fileName, year, month,
      client, receivedDate, receivedAmount: toNum(amount),
      project: extract('案件', text) || ''
    }});
    continue;
  }
}
return results;

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  try {
    const workbook = new ExcelJS.Workbook();
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    await workbook.xlsx.load(buffer);

    const toDate = (dateStr) => {
      const p = dateStr.split('/');
      return new Date(Date.UTC(parseInt(p[0]), parseInt(p[1])-1, parseInt(p[2])));
    };

    const findLastRow = (sheet, keyCol) => {
      let last = 1;
      sheet.eachRow((row, num) => { if (num >= 2 && row.getCell(keyCol).value) last = num; });
      return last;
    };

    const mt = data.messageType;

    // ===== 経費 =====
    if (mt === 'expense') {
      const sheet = workbook.getWorksheet('経費');
      if (!sheet) throw new Error('経費シートが見つかりません');
      const r = findLastRow(sheet, 2) + 1;
      sheet.getRow(r).getCell(2).value = toDate(data.date);
      sheet.getRow(r).getCell(2).numFmt = 'YYYY/MM/DD';
      sheet.getRow(r).getCell(3).value = data.category;
      sheet.getRow(r).getCell(4).value = data.paymentMethod;
      sheet.getRow(r).getCell(5).value = data.store;
      sheet.getRow(r).getCell(6).value = data.project;
      sheet.getRow(r).getCell(7).value = data.amount;
      sheet.getRow(r).getCell(7).numFmt = '#,##0';
      sheet.getRow(r).getCell(8).value = data.note;
    }

    // ===== 外注請求 =====
    else if (mt === 'subcontractor_invoice') {
      const sheet = workbook.getWorksheet('外注管理');
      if (!sheet) throw new Error('外注管理シートが見つかりません');
      const r = findLastRow(sheet, 3) + 1;
      sheet.getRow(r).getCell(2).value = toDate(data.registrationDate);
      sheet.getRow(r).getCell(2).numFmt = 'YYYY/MM/DD';
      sheet.getRow(r).getCell(3).value = data.vendor;
      sheet.getRow(r).getCell(6).value = data.project;
      sheet.getRow(r).getCell(7).value = data.amountExTax;
      sheet.getRow(r).getCell(7).numFmt = '#,##0';
      sheet.getRow(r).getCell(8).value = data.tax;
      sheet.getRow(r).getCell(8).numFmt = '#,##0';
      sheet.getRow(r).getCell(9).value = data.total;
      sheet.getRow(r).getCell(9).numFmt = '#,##0';
      sheet.getRow(r).getCell(10).value = toDate(data.invoiceDate);
      sheet.getRow(r).getCell(10).numFmt = 'YYYY/MM/DD';
    }

    // ===== 外注支払 =====
    else if (mt === 'subcontractor_payment') {
      const sheet = workbook.getWorksheet('外注管理');
      if (!sheet) throw new Error('外注管理シートが見つかりません');
      let targetRow = null;
      sheet.eachRow((row, num) => {
        if (num < 2 || targetRow) return;
        const vendor = row.getCell(3).value;
        const statusCell = row.getCell(14).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        if (vendor === data.vendor && status === '未払') targetRow = row;
      });
      if (!targetRow) return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: `${data.vendor}の未払い請求が見つかりません` } }];
      targetRow.getCell(12).value = toDate(data.paymentDate);
      targetRow.getCell(12).numFmt = 'YYYY/MM/DD';
      targetRow.getCell(13).value = data.paymentAmount;
      targetRow.getCell(13).numFmt = '#,##0';
    }

    // ===== 売上 =====
    else if (mt === 'sales') {
      const sheet = workbook.getWorksheet('売上管理');
      if (!sheet) throw new Error('売上管理シートが見つかりません');
      const r = findLastRow(sheet, 3) + 1;
      sheet.getRow(r).getCell(2).value = toDate(data.registrationDate);
      sheet.getRow(r).getCell(2).numFmt = 'YYYY/MM/DD';
      sheet.getRow(r).getCell(3).value = data.client;
      sheet.getRow(r).getCell(4).value = data.project;
      sheet.getRow(r).getCell(5).value = data.amountExTax;
      sheet.getRow(r).getCell(5).numFmt = '#,##0';
      sheet.getRow(r).getCell(6).value = data.tax;
      sheet.getRow(r).getCell(6).numFmt = '#,##0';
      sheet.getRow(r).getCell(7).value = data.total;
      sheet.getRow(r).getCell(7).numFmt = '#,##0';
      sheet.getRow(r).getCell(8).value = toDate(data.invoiceDate);
      sheet.getRow(r).getCell(8).numFmt = 'YYYY/MM/DD';
      if (data.dueDate) {
        sheet.getRow(r).getCell(9).value = toDate(data.dueDate);
        sheet.getRow(r).getCell(9).numFmt = 'YYYY/MM/DD';
      }
    }

    // ===== 入金 =====
    else if (mt === 'payment_received') {
      const sheet = workbook.getWorksheet('売上管理');
      if (!sheet) throw new Error('売上管理シートが見つかりません');
      let targetRow = null;
      sheet.eachRow((row, num) => {
        if (num < 2 || targetRow) return;
        const client = row.getCell(3).value;
        const statusCell = row.getCell(12).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        if (client === data.client && status === '未入金') targetRow = row;
      });
      if (!targetRow) return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: `${data.client}の未入金請求が見つかりません` } }];
      targetRow.getCell(10).value = toDate(data.receivedDate);
      targetRow.getCell(10).numFmt = 'YYYY/MM/DD';
      targetRow.getCell(11).value = data.receivedAmount;
      targetRow.getCell(11).numFmt = '#,##0';
    }

    const outBuffer = await workbook.xlsx.writeBuffer({ useSharedStrings: false });
    const binaryData = await this.helpers.prepareBinaryData(Buffer.from(outBuffer), data.fileName, 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    return [{ json: { ...data, fileId: $input.item.json.fileId, valid: true }, binary: { data: binaryData } }];

  } catch (error) {
    return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: `処理エラー: ${error.message}` } }];
  }
})();

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  try {
    const workbook = new ExcelJS.Workbook();
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    await workbook.xlsx.load(buffer);

    const fmt = (n) => n ? n.toLocaleString('ja-JP') : '0';

    // ===== 未払い確認 =====
    if (data.messageType === 'query_unpaid') {
      const sheet = workbook.getWorksheet('外注管理');
      const unpaid = [];
      sheet.eachRow((row, num) => {
        if (num < 2) return;
        const vendor = row.getCell(3).value;
        if (!vendor) return;
        const statusCell = row.getCell(14).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        if (status !== '未払') return;
        const project = row.getCell(6).value || '';
        const totalCell = row.getCell(9).value;
        const total = (totalCell && typeof totalCell === 'object' && 'result' in totalCell) ? totalCell.result : totalCell;
        const limitCell = row.getCell(11).value;
        const limit = (limitCell && typeof limitCell === 'object' && 'result' in limitCell) ? limitCell.result : limitCell;
        const limitStr = limit ? `${limit.getUTCFullYear()}/${limit.getUTCMonth()+1}/${limit.getUTCDate()}` : '期限不明';
        unpaid.push(`${vendor}\n  ${project}\n  ¥${fmt(total)}  期限:${limitStr}`);
      });
      const msg = unpaid.length > 0
        ? `【未払い一覧】${data.year}年${data.month}月\n\n${unpaid.join('\n\n')}\n\n合計 ${unpaid.length}件`
        : `【未払い一覧】${data.year}年${data.month}月\n\n未払いはありません`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }

    // ===== 未入金確認 =====
    if (data.messageType === 'query_unreceived') {
      const sheet = workbook.getWorksheet('売上管理');
      const unreceived = [];
      sheet.eachRow((row, num) => {
        if (num < 2) return;
        const client = row.getCell(3).value;
        if (!client) return;
        const statusCell = row.getCell(12).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        if (status !== '未入金') return;
        const project = row.getCell(4).value || '';
        const totalCell = row.getCell(7).value;
        const total = (totalCell && typeof totalCell === 'object' && 'result' in totalCell) ? totalCell.result : totalCell;
        const dueCell = row.getCell(9).value;
        const due = dueCell instanceof Date ? `${dueCell.getUTCFullYear()}/${dueCell.getUTCMonth()+1}/${dueCell.getUTCDate()}` : '期限未設定';
        unreceived.push(`${client}\n  ${project}\n  ¥${fmt(total)}  期限:${due}`);
      });
      const msg = unreceived.length > 0
        ? `【未入金一覧】${data.year}年${data.month}月\n\n${unreceived.join('\n\n')}\n\n合計 ${unreceived.length}件`
        : `【未入金一覧】${data.year}年${data.month}月\n\n未入金はありません`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }

    // ===== 今月サマリー =====
    if (data.messageType === 'query_summary') {
      let salesTotal = 0, receivedTotal = 0, unreceived = 0;
      let subTotal = 0, paidTotal = 0, unpaidTotal = 0;
      let expenseTotal = 0;

      const salesSheet = workbook.getWorksheet('売上管理');
      salesSheet.eachRow((row, num) => {
        if (num < 2) return;
        if (!row.getCell(3).value) return;
        const totalCell = row.getCell(7).value;
        const total = (totalCell && typeof totalCell === 'object' && 'result' in totalCell) ? totalCell.result : (totalCell || 0);
        const statusCell = row.getCell(12).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        salesTotal += total || 0;
        if (status === '入金済') receivedTotal += (row.getCell(11).value || 0);
        if (status === '未入金') unreceived += total || 0;
      });

      const subSheet = workbook.getWorksheet('外注管理');
      subSheet.eachRow((row, num) => {
        if (num < 2) return;
        if (!row.getCell(3).value) return;
        const totalCell = row.getCell(9).value;
        const total = (totalCell && typeof totalCell === 'object' && 'result' in totalCell) ? totalCell.result : (totalCell || 0);
        const statusCell = row.getCell(14).value;
        const status = (statusCell && typeof statusCell === 'object' && 'result' in statusCell) ? statusCell.result : statusCell;
        subTotal += total || 0;
        if (status === '支払済') paidTotal += (row.getCell(13).value || 0);
        if (status === '未払') unpaidTotal += total || 0;
      });

      const expSheet = workbook.getWorksheet('経費');
      expSheet.eachRow((row, num) => {
        if (num < 2) return;
        expenseTotal += row.getCell(7).value || 0;
      });

      const gross = salesTotal - subTotal - expenseTotal;
      const msg = `【今月サマリー】${data.year}年${data.month}月\n\n` +
        `■ 売上\n  請求済  ¥${fmt(salesTotal)}\n  入金済  ¥${fmt(receivedTotal)}\n  未入金  ¥${fmt(unreceived)}\n\n` +
        `■ 外注費\n  請求受取  ¥${fmt(subTotal)}\n  支払済  ¥${fmt(paidTotal)}\n  未払い  ¥${fmt(unpaidTotal)}\n\n` +
        `■ 経費\n  合計  ¥${fmt(expenseTotal)}\n\n` +
        `■ 粗利（概算）\n  ¥${fmt(gross)}`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }

    return [{ json: { replyToken: data.replyToken, replyMessage: '不明なコマンドです' } }];
  } catch (error) {
    return [{ json: { replyToken: data.replyToken, replyMessage: `エラー: ${error.message}` } }];
  }
})();

const data = $('LINEメッセージ解析').first().json;
const mt = data.messageType;
const msgs = {
  expense:                `✅ 経費を記録しました

日付: ${data.date}
種類: ${data.category}
支払方法: ${data.paymentMethod}
店名: ${data.store}
金額: ¥${(data.amount||0).toLocaleString('ja-JP')}`,
  subcontractor_invoice:  `✅ 外注請求を記録しました

業者: ${data.vendor}
案件: ${data.project}
請求額: ¥${(data.amountExTax||0).toLocaleString('ja-JP')}
消費税: ¥${(data.tax||0).toLocaleString('ja-JP')}
合計: ¥${(data.total||0).toLocaleString('ja-JP')}
請求日: ${data.invoiceDate}`,
  subcontractor_payment:  `✅ 外注支払を記録しました

業者: ${data.vendor}
支払日: ${data.paymentDate}
支払額: ¥${(data.paymentAmount||0).toLocaleString('ja-JP')}`,
  sales:                  `✅ 売上を記録しました

得意先: ${data.client}
案件: ${data.project}
請求額: ¥${(data.amountExTax||0).toLocaleString('ja-JP')}
消費税: ¥${(data.tax||0).toLocaleString('ja-JP')}
合計: ¥${(data.total||0).toLocaleString('ja-JP')}
請求日: ${data.invoiceDate}`,
  payment_received:       `✅ 入金を記録しました

得意先: ${data.client}
入金日: ${data.receivedDate}
入金額: ¥${(data.receivedAmount||0).toLocaleString('ja-JP')}`
};
const replyMessage = msgs[mt] || '✅ 記録しました';
return [{ json: { replyToken: data.replyToken, replyMessage } }];

// fileId をファイル情報JSONから取得して次ノードに渡す
const fileInfo = $input.item.json;
const msgData = $('LINEメッセージ解析').first().json;
return [{ json: { ...msgData, fileId: fileInfo.id } }];
